using Bunit;
using Microsoft.AspNetCore.Components;
using MudBlazor;
using MudBlazor.UnitTests.Shared.Extensions;

var items = new[] { new Item("B", 2), new Item("A", 1) };
var snapshots = new List<Dictionary<string, SortDefinition<Item>>>();

using var context = new BunitContext();
context.AddTestServices();
var component = context.RenderComponent<MudDataGrid<Item>>(parameters => parameters
    .Add(x => x.Items, items)
    .Add(x => x.SortMode, SortMode.Multiple)
    .Add(x => x.SortChanged, EventCallback.Factory.Create<Dictionary<string, SortDefinition<Item>>>(
        new object(),
        (Dictionary<string, SortDefinition<Item>> definitions) =>
        {
            snapshots.Add(definitions);
            return Task.CompletedTask;
        })));
var grid = component.Instance;

await component.InvokeAsync(() => grid.SetSortAsync(nameof(Item.Name), SortDirection.Ascending, item => item.Name));
Require(snapshots.Count == 1, "SetSortAsync should raise SortChanged once.");
Require(snapshots[0].Count == 1 && !snapshots[0][nameof(Item.Name)].Descending, "SetSortAsync snapshot should contain ascending Name sort.");
Require(!ReferenceEquals(snapshots[0], grid.SortDefinitions), "SortChanged should receive a copy of SortDefinitions.");

await component.InvokeAsync(() => grid.ExtendSortAsync(nameof(Item.Age), SortDirection.Descending, item => item.Age));
Require(snapshots.Count == 2, "ExtendSortAsync should raise SortChanged once.");
Require(snapshots[1].Count == 2 && snapshots[1][nameof(Item.Age)].Descending, "ExtendSortAsync snapshot should contain descending Age sort.");

await component.InvokeAsync(() => grid.RemoveSortAsync(nameof(Item.Name)));
Require(snapshots.Count == 3, "RemoveSortAsync should raise SortChanged once.");
Require(!snapshots[2].ContainsKey(nameof(Item.Name)) && snapshots[2].ContainsKey(nameof(Item.Age)), "RemoveSortAsync snapshot should remove Name and retain Age.");

await component.InvokeAsync(() => grid.RemoveSortAsync(nameof(Item.Age)));
Require(snapshots.Count == 4, "Removing final sort should raise SortChanged once.");
Require(snapshots[3].Count == 0, "Final snapshot should be empty after removing all sorts.");

Console.WriteLine("SortChanged fired for set, extend, remove, and clear-to-empty scenarios.");

static void Require(bool condition, string message)
{
    if (!condition)
    {
        throw new InvalidOperationException(message);
    }
}

public sealed record Item(string Name, int Age);
